          <div style={{ fontSize: '16px', fontWeight: '600', fontFamily: 'monospace' }}>{currentBatch}</div>
        </div>

        <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
          {MOCK_INVENTORY.map(stock => (
            <div 
              key={stock.batchNo}
              onClick={() => !stock.isLocked && onSelect(stock.batchNo)}
              style={{ 
                padding: '16px', 
                borderRadius: '8px',
                border: stock.batchNo === currentBatch ? '2px solid var(--accent)' : '1px solid var(--border)',
                background: stock.isLocked ? '#f1f5f9' : 'white',
                opacity: stock.isLocked ? 0.7 : 1,
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center',
                cursor: stock.isLocked ? 'not-allowed' : 'pointer'
              }}
            >
              <div>
                <div style={{ fontWeight: '600', display: 'flex', alignItems: 'center', gap: '8px' }}>
                  {stock.batchNo}
                  {stock.isLocked && <span style={{ fontSize: '10px', background: '#fee2e2', color: '#ef4444', padding: '2px 6px', borderRadius: '4px' }}>LOCKED</span>}
                </div>
                <div style={{ fontSize: '12px', color: '#64748b', marginTop: '4px' }}>Exp: {stock.expiryDate}</div>
              </div>
              <div style={{ textAlign: 'right' }}>
                <div style={{ fontWeight: '600', color: 'var(--success)' }}>{stock.qty} Box</div>
                <div style={{ fontSize: '12px', color: '#94a3b8' }}>Available</div>
              </div>
            </div>
          ))}
