            <span style={{ fontSize: '13px', fontWeight: '600' }}>Pick Quantity</span>
            <span style={{ fontSize: '13px', color: '#64748b' }}>Plan: <b>{currentItem.planQty}</b></span>
          </div>

          <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
            <button 
              onClick={() => {
                const val = parseInt(inputQty) || 0;
                if(val > 0) setInputQty((val - 1).toString());
              }}
              style={{ width: '40px', height: '40px', borderRadius: '8px', border: '1px solid var(--border)', background: 'white', fontSize: '18px' }}
            >-</button>
            <div style={{ flex: 1, position: 'relative' }}>
              <input 
                type="number" 
                value={inputQty}
                onChange={(e) => setInputQty(e.target.value)}
                style={{ 
                  width: '100%', height: '40px', textAlign: 'center', 
                  fontSize: '18px', fontWeight: '600',
                  borderRadius: '8px', border: '1px solid var(--border)',
                  color: 'var(--primary)'
                }}
              />
              <span style={{ position: 'absolute', right: '10px', top: '10px', fontSize: '12px', color: '#94a3b8' }}>BOX</span>
            </div>
            <button 
              onClick={() => {
                 const val = parseInt(inputQty) || 0;
                 if(val < currentItem.planQty) setInputQty((val + 1).toString());
              }}
              style={{ width: '40px', height: '40px', borderRadius: '8px', border: '1px solid var(--border)', background: 'white', fontSize: '18px' }}
            >+</button>
          </div>
        </div>

        {/* Error Message */}
        {errorMsg && (
          <div style={{ 
            padding: '12px', background: '#fef2f2', color: '#ef4444', 
            borderRadius: '8px', marginBottom: '16px', fontSize: '13px',
            display: 'flex', alignItems: 'center', gap: '8px'
          }}>
            <IconAlert size={16} /> {errorMsg}
          </div>
        )}
      </div>

      {/* Footer / Action Bar */}
      <div style={{ 
        position: 'fixed', bottom: 0, left: 0, right: 0, 
        background: 'white', padding: '16px', 
        borderTop: '1px solid var(--border)',
        boxShadow: '0 -4px 6px -1px rgba(0,0,0,0.05)'
      }}>
        <button 
          onClick={handleConfirm}
          disabled={isLocationMode && (!isLocationValid || !isBatchValid)}
          style={{ 
            width: '100%', padding: '14px', 
            background: (isLocationMode && (!isLocationValid || !isBatchValid)) ? '#94a3b8' : 'var(--success)', 
            color: 'white', 
            border: 'none', borderRadius: '12px',
            fontSize: '16px', fontWeight: '600',
            display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '8px',
            boxShadow: '0 4px 6px -1px rgba(22, 163, 74, 0.3)'
          }}
        >
          {currentIndex === items.length - 1 ? 'Complete Order' : 'Confirm & Next'}
        </button>
      </div>

      <BatchSelector 
        isOpen={showBatchModal}
        onClose={() => setShowBatchModal(false)}
        onSelect={handleChangeBatch}
        currentBatch={targetBatch}
      />
    </div>
  );
};

